import json
import pickle
import base64

def lambda_handler(event, context):
    try:
        # Decode the base64 encoded body
        body = base64.b64decode(event['body'])
        
        # Deserialize the JSON payload
        payload = json.loads(body)
        
        # Extract the user actions
        user_actions = payload.get('user_actions', [])
        
        # Process each user action
        for action in user_actions:
            # Serialize the action using pickle
            serialized_action = pickle.dumps(action, protocol=pickle.HIGHEST_PROTOCOL)
            
            # Process the serialized action (example processing)
            process_action(serialized_action)
        
        return {
            'statusCode': 200,
            'body': json.dumps({'message': 'Success'})
        }
    except Exception as e:
        return {
            'statusCode': 500,
            'body': json.dumps({'error': str(e)})
        }

def process_action(serialized_action):
    # Example processing function
    action = pickle.loads(serialized_action)
    # Perform necessary operations on the action
    print(action)